-- ============================================================
-- KIEMO MENS WEAR — Phase 2 migration: products table + seed
--
-- Creates the dashboard-ready products table and seeds it with the exact
-- same 87 products currently served from data/products.ts. The live
-- storefront keeps reading from data/products.ts in Phase 2 — this table
-- exists so it's populated and ready for Phase 4's admin dashboard
-- (Products CRUD) to switch the site over to reading from Supabase
-- directly, without a risky "flip the data source" step happening at the
-- same time as new UI. Re-running this file is safe: the seed uses
-- ON CONFLICT DO NOTHING.
-- ============================================================

create table if not exists public.products (
  id integer primary key,
  sku text unique not null,
  slug text unique not null,
  name text not null,
  category text not null,
  subcategory text,
  price numeric(12, 2) not null check (price >= 0),
  old_price numeric(12, 2) check (old_price is null or old_price >= 0),
  is_new boolean not null default false,
  is_offer boolean not null default false,
  featured boolean not null default false,
  stock integer,
  sizes text[] not null default '{}',
  colors text[] not null default '{}',
  unavailable text[] not null default '{}',
  img text not null,
  images text[] not null default '{}',
  description text,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create index if not exists products_category_idx on public.products (category);
create index if not exists products_featured_idx on public.products (featured) where featured = true;
create index if not exists products_is_new_idx on public.products (is_new) where is_new = true;
create index if not exists products_is_offer_idx on public.products (is_offer) where is_offer = true;

-- updated_at auto-touch, so Phase 4's dashboard edits don't need to
-- remember to set it manually.
create or replace function public.touch_updated_at()
returns trigger
language plpgsql
as $$
begin
  new.updated_at = now();
  return new;
end;
$$;

drop trigger if exists products_touch_updated_at on public.products;
create trigger products_touch_updated_at
  before update on public.products
  for each row execute function public.touch_updated_at();

alter table public.products enable row level security;

drop policy if exists "Public can read products" on public.products;
create policy "Public can read products" on public.products
  for select using (true);
-- No insert/update/delete policy for anon/authenticated — the catalog is
-- read-only to the public. Only the service role (Phase 4's admin API
-- routes) can write, same pattern as orders in Phase 1.

